=You are the Orchestrator Agent. Analyze this research request: "{{ $json.query }}"

Respond with ONLY this JSON and nothing else:
{"main_topic": "exact topic", "aspect_1": "first research angle", "aspect_2": "latest news angle", "aspect_3": "competitive market angle", "research_type": "mixed"}

parameters.jsCode:
const raw = $input.item.json.text || '';
const query = $('Validate Input').item.json.query;

let plan = {};
try {
  let clean = raw.trim();
  if (clean.includes('```json')) clean = clean.split('```json')[1].split('```')[0].trim();
  else if (clean.includes('```')) clean = clean.split('```')[1].split('```')[0].trim();
  const match = clean.match(/\{[\s\S]*\}/);
  if (match) plan = JSON.parse(match[0]);
} catch(e) { plan = {}; }

return {
  json: {
    original_query: query,
    main_topic: plan.main_topic || query,
    aspect_1: plan.aspect_1 || 'overview and key facts',
    aspect_2: plan.aspect_2 || 'latest news and developments',
    aspect_3: plan.aspect_3 || 'competitive landscape and trends',
    research_type: plan.research_type || 'mixed'
  }
};

const searchText = $input.item.json.text || 'No search data available';
const prev = $('Parse Plan').item.json;
return {
  json: {
    original_query: prev.original_query,
    main_topic: prev.main_topic,
